// ─── SEED FUNCTIONS ───────────────────────────────────────────────────────────

async function seed(collection, items) {
  let count = 0;
  for (const item of items) {
    const { id, ...data } = item;
    await db.collection(collection).doc(id).set(data);
    count++;
    process.stdout.write(`\r  ${collection}: ${count}/${items.length}`);
  }
  console.log(`  ✓ ${collection} (${count})`);
}

async function main() {
  console.log('\n🌱  Seeding KeyHub Central demo data...\n');
  await seed('campaigns',   CAMPAIGNS);
  await seed('contractors', CONTRACTORS);
  await seed('leads',       LEADS);
  await seed('jobs',        JOBS);
  await seed('invoices',    INVOICES);
  console.log('\n✅  Done! 100 documents written.\n');
}

main().catch(err => { console.error('\n❌ Seed failed:', err.message); process.exit(1); });
